python3 << 'EOF'
import json
import re

# Load files
with open('manifest.json') as f:
    manifest = json.load(f)

with open('schema.json') as f:
    schema = json.load(f)

# Manual validation against schema
errors = []

# Check required fields
if "release" not in manifest:
    errors.append("Missing 'release' field")
if "components" not in manifest:
    errors.append("Missing 'components' field")

# Check release format
if "release" in manifest:
    release = manifest["release"]
    if not isinstance(release, str):
        errors.append(f"'release' must be string, got {type(release).__name__}")
    elif not re.match(r"^v[0-9]+\.[0-9]+\.[0-9]+$", release):
        errors.append(f"'release' doesn't match pattern: {release}")

# Check components
if "components" in manifest:
    components = manifest["components"]
    if not isinstance(components, list):
        errors.append(f"'components' must be array, got {type(components).__name__}")
    elif len(components) != 3:
        errors.append(f"'components' must have exactly 3 items, got {len(components)}")
    elif len(components) != len(set(json.dumps(c, sort_keys=True) for c in components)):
        errors.append("'components' has duplicate items")
    else:
        for i, comp in enumerate(components):
            if not isinstance(comp, dict):
                errors.append(f"components[{i}] must be object, got {type(comp).__name__}")
            else:
                # Check required properties
                if "name" not in comp:
                    errors.append(f"components[{i}] missing 'name'")
                if "version" not in comp:
                    errors.append(f"components[{i}] missing 'version'")

                # Check no extra properties
                valid_props = {"name", "version"}
                extra_props = set(comp.keys()) - valid_props
                if extra_props:
                    errors.append(f"components[{i}] has extra properties: {extra_props}")

                # Check name is string
                if "name" in comp and not isinstance(comp["name"], str):
                    errors.append(f"components[{i}].name must be string")

                # Check version format
                if "version" in comp:
                    version = comp["version"]
                    if not isinstance(version, str):
                        errors.append(f"components[{i}].version must be string")
                    elif not re.match(r"^[0-9]+\.[0-9]+\.[0-9]+$", version):
                        errors.append(f"components[{i}].version doesn't match semver: {version}")

# Check no extra properties at root
valid_root_props = {"release", "components"}
extra_root_props = set(manifest.keys()) - valid_root_props
if extra_root_props:
    errors.append(f"Root has extra properties: {extra_root_props}")

# Report results
if errors:
    print("VALIDATION FAILED:")
    for error in errors:
        print(f"  ✗ {error}")
    exit(1)
else:
    print("✓ manifest.json validates successfully against schema.json")
    print("\nManifest structure:")
    print(f"  - release: {manifest['release']}")
    print(f"  - components: {len(manifest['components'])} items")
    for i, comp in enumerate(manifest['components'], 1):
        print(f"    {i}. {comp['name']} {comp['version']}")
    exit(0)
EOF

