python3 << 'EOF'
import json
import re

with open('manifest.json', 'r') as f:
    content = f.read()
    data = json.loads(content)

# Privacy patterns to check
privacy_patterns = [
    (r'(api[_-]?key|apikey)', 'API Key'),
    (r'(password|passwd|pwd)', 'Password'),
    (r'(secret|token)', 'Secret/Token'),
    (r'(private[_-]?key|privatekey)', 'Private Key'),
    (r'(aws|azure|gcp)[_-]?[a-z]*[_-]?key', 'Cloud credentials'),
    (r'(bearer\s+[a-z0-9]+|authorization\s+[a-z0-9]+)', 'Authorization header'),
]

issues = []

# Check raw content (case-insensitive)
content_lower = content.lower()
for pattern, desc in privacy_patterns:
    if re.search(pattern, content_lower):
        issues.append(f"{desc} pattern detected")

# Check all values
def check_values(obj, path=""):
    if isinstance(obj, dict):
        for key, value in obj.items():
            check_values(value, f"{path}.{key}" if path else key)
    elif isinstance(obj, list):
        for i, item in enumerate(obj):
            check_values(item, f"{path}[{i}]")
    elif isinstance(obj, str):
        if len(obj) > 200:
            issues.append(f"Suspiciously long string at '{path}'")

check_values(data)

if issues:
    print("Privacy scan results:")
    for issue in issues:
        print(f"  ⚠ {issue}")
    exit(1)
else:
    print("✓ Privacy scan: zero hits")
    print("  No API keys, passwords, tokens, or sensitive data detected")
    exit(0)
EOF
